// Time:  O(n)
// Space: O(1)

class Solution {
public:
    int countPalindromicSubsequence(string s) {
        vector<int> first(26, size(s));
        vector<int> last(26, -1);
        for (int i = 0; i < size(s); ++i) {
            first[s[i] - 'a'] = min(first[s[i] - 'a'], i);
            last[s[i] - 'a'] = max(last[s[i] - 'a'], i);
        }
        int result = 0;
        for (int i = 0; i < 26; ++i) {
            if (first[i] < last[i]) {
                result += size(unordered_set<char>(cbegin(s) + first[i] + 1, cbegin(s) + last[i]));
            }
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(1)

class Solution(object):
    def countPalindromicSubsequence(self, s):
        """
        :type s: str
        :rtype: int
        """
        first, last = [len(s)]*26, [-1]*26
        for i, c in enumerate(s):
            first[ord(c)-ord('a')] = min(first[ord(c)-ord('a')], i)
            last[ord(c)-ord('a')] = max(last[ord(c)-ord('a')], i)
        return sum(len(set(s[i] for i in xrange(first[c]+1, last[c]))) for c in xrange(26))
